SELECT AVG(track_count) AS avg_tracks_per_album
FROM (
    SELECT AlbumId, COUNT(*) AS track_count
    FROM Track
    GROUP BY AlbumId
);

SELECT e.FirstName, e.LastName, e.Title
FROM Employee e
WHERE e.EmployeeId NOT IN (
    SELECT DISTINCT ReportsTo FROM Employee WHERE ReportsTo IS NOT NULL
)
ORDER BY e.LastName, e.FirstName;
